SELECT 
FROM `project_role_grant`
WHERE `project_id` = #{projectId, jdbcType=BIGINT}
  AND `grant_role_code` = #{grantRoleCode, jdbcType=VARCHAR}
  AND `status` = 'ACTIVE'
ORDER BY `created_at` DESC, `project_role_grant_id` DESC

SELECT 
FROM `project_role_grant`
WHERE `grantee_user_id` = #{granteeUserId, jdbcType=BIGINT}
  AND `project_id` = #{projectId, jdbcType=BIGINT}
  AND `status` = 'ACTIVE'
ORDER BY `created_at` DESC, `project_role_grant_id` DESC

SELECT 
FROM `project_role_grant`
WHERE `project_id` = #{projectId, jdbcType=BIGINT}
  AND `grant_role_code` = #{grantRoleCode, jdbcType=VARCHAR}
  AND `grantee_user_id` = #{granteeUserId, jdbcType=BIGINT}
  AND `status` = 'ACTIVE'
  AND (
    (#{moduleType, jdbcType=VARCHAR} IS NULL AND `module_type` IS NULL)
    OR `module_type` = #{moduleType, jdbcType=VARCHAR}
  )
  AND (
    (#{roundNo, jdbcType=INTEGER} IS NULL AND `round_no` IS NULL)
    OR `round_no` = #{roundNo, jdbcType=INTEGER}
  )
  AND (
    (#{taskNodeId, jdbcType=VARCHAR} IS NULL AND `task_node_id` IS NULL)
    OR `task_node_id` = #{taskNodeId, jdbcType=VARCHAR}
  )
ORDER BY `created_at` DESC, `project_role_grant_id` DESC

